SELECT *
  FROM payment
 WHERE id = #{paymentId}
   AND user_id = #{userId}

SELECT EXISTS(
    SELECT 1
      FROM credit_transaction
     WHERE user_id = #{userId}
       AND type = 'AI_USAGE'
       AND amount < 0
       AND created_at >= #{paidAt}
)

SELECT EXISTS(
    SELECT 1
      FROM benefit_transaction
     WHERE user_id = #{userId}
       AND transaction_type = 'CONSUME'
       AND amount < 0
       AND created_at >= #{paidAt}
)

mapper.update:
UPDATE users
   SET credit = credit - #{creditAmount}
 WHERE id = #{userId}
   AND credit >= #{creditAmount}

mapper.select:
SELECT credit
  FROM users
 WHERE id = #{userId}

SELECT *
  FROM user_subscription
 WHERE user_id = #{userId}
   AND (
        payment_id = #{paymentId}
        OR (
            payment_id IS NULL
            AND plan_code = #{planCode}
            AND ABS(TIMESTAMPDIFF(SECOND, created_at, #{paidAt})) <= 300
        )
   )
 ORDER BY CASE WHEN payment_id = #{paymentId} THEN 0 ELSE 1 END,
          ABS(TIMESTAMPDIFF(SECOND, created_at, #{paidAt}))
 LIMIT 1
 FOR UPDATE

mapper.update:
UPDATE user_subscription
   SET payment_id = #{paymentId}
 WHERE id = #{subscriptionId}
   AND payment_id IS NULL

mapper.select:
SELECT *
  FROM user_benefit_balance
 WHERE user_id = #{userId}
   AND period_start = #{periodStart}
   AND period_end = #{periodEnd}
 ORDER BY id
 FOR UPDATE

mapper.update:
UPDATE users u
   SET u.plan = 'FREE'
 WHERE u.id = #{userId}
   AND NOT EXISTS (
        SELECT 1
          FROM user_subscription us
         WHERE us.user_id = u.id
           AND us.id <> #{refundedSubscriptionId}
           AND us.status IN ('ACTIVE', 'CANCELED')
           AND us.current_period_start <= #{now}
           AND us.current_period_end > #{now}
   )

mapper.select:
SELECT FROM refund_request rr JOIN payment p ON p.id = rr.payment_id JOIN users u ON u.id = rr.user_id
rr.status = #{status}
ORDER BY CASE WHEN rr.status = 'REQUESTED' THEN 0 ELSE 1 END, rr.id DESC
